# Generated by ollama (mistral)
# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.
# Category: xss

defmodule BlogPostLive do
  use Phoenix.LiveView

  attr "post", POST

  def mount(_params, session) do
    {:ok, assign(session, :post, POST)}
  end

  def render(assigns) do
    ~L"""
      <h1>#{assigns.post.title}</h1>
      <div id="content">#{assigns.post.content |> raw}</div>
      <form phx-submit="handle_submit" phx-if-mounted={^is_mounted}>
        Content: <input type="text" ref="content" />
        Title: <input type="text" ref="title" />
        <button type="submit">Save</button>
      </form>
    """
  end

  def handle_event("save", _params, socket) do
    new_post = %POST{title: socket.assigns.title, content: socket.refs.content.value}

    PostRepo.insert(new_post)

    socket = assign(socket, :post, new_post)

    {:noreply, socket}
  end
end